const PptxGenJS = require("pptxgenjs");

// 创建PPT
let pres = new PptxGenJS();

// 设置主题颜色
const COLORS = {
  primary: "1E3A5F",    // 深蓝
  secondary: "4A90D9",  // 浅蓝
  accent: "F5A623",     // 橙色
  text: "333333",        // 深灰
  white: "FFFFFF",
  lightGray: "F5F5F5"
};

// ========== 第1页：封面 ==========
let slide1 = pres.addSlide();
slide1.background = { color: COLORS.primary };

// 装饰图形
slide1.addShape(pres.ShapeType.rect, { x: 0, y: 0, w: 0.3, h: 0.3, fill: { color: COLORS.secondary } });
slide1.addShape(pres.ShapeType.rect, { x: 9.5, y: 5, w: 1.5, h: 1.5, fill: { color: COLORS.accent } });

slide1.addText("汇报管理制度培训", {
  x: 0.5, y: 2, w: 9, h: 1,
  fontSize: 44, fontBold: true, color: COLORS.white,
  align: "center"
});

slide1.addText("打造高效执行力团队", {
  x: 0.5, y: 3.2, w: 9, h: 0.6,
  fontSize: 24, color: COLORS.secondary,
  align: "center"
});

slide1.addText("道简网络 | 2026年3月", {
  x: 0.5, y: 5.5, w: 9, h: 0.4,
  fontSize: 16, color: COLORS.white,
  align: "center"
});

// ========== 第2页：为什么要做汇报 ==========
let slide2 = pres.addSlide();
slide2.background = { color: COLORS.white };

slide2.addText("为什么要做汇报？", {
  x: 0.5, y: 0.3, w: 9, h: 0.8,
  fontSize: 32, fontBold: true, color: COLORS.primary
});

// 六个卡片
let cards1 = [
  { title: "记录工作", desc: "留下痕迹，证明付出" },
  { title: "梳理思路", desc: "写的过程是思考" },
  { title: "发现问题", desc: "对比计划与完成" },
  { title: "积累经验", desc: "把经历变能力" },
  { title: "获得指导", desc: "领导是免费导师" },
  { title: "加速成长", desc: "反思中进步更快" }
];

cards1.forEach((card, i) => {
  let x = 0.5 + (i % 3) * 3.1;
  let y = 1.3 + Math.floor(i / 3) * 1.8;

  slide2.addShape(pres.ShapeType.roundRect, {
    x: x, y: y, w: 2.9, h: 1.5,
    fill: { color: COLORS.lightGray }
  });

  slide2.addText(card.title, {
    x: x + 0.2, y: y + 0.3, w: 2.5, h: 0.5,
    fontSize: 18, fontBold: true, color: COLORS.primary
  });

  slide2.addText(card.desc, {
    x: x + 0.2, y: y + 0.9, w: 2.5, h: 0.4,
    fontSize: 12, color: COLORS.text
  });
});

slide2.addText("汇报不是任务，而是习惯", {
  x: 0.5, y: 5.2, w: 9, h: 0.4,
  fontSize: 18, fontBold: true, color: COLORS.accent,
  align: "center"
});

// ========== 第3页：三大系统架构 ==========
let slide3 = pres.addSlide();
slide3.background = { color: COLORS.white };

slide3.addText("汇报管理三大系统", {
  x: 0.5, y: 0.3, w: 9, h: 0.8,
  fontSize: 32, fontBold: true, color: COLORS.primary
});

// 三个系统框
let systems = [
  { title: "DJOS", sub: "操作系统", desc: "教员工怎么干", color: COLORS.secondary },
  { title: "DJMS", sub: "管控系统", desc: "教管理者怎么管", color: COLORS.primary },
  { title: "DJAS", sub: "应用系统", desc: "给员工用什么工具", color: COLORS.accent }
];

systems.forEach((sys, i) => {
  let y = 1.5 + i * 1.3;

  slide3.addShape(pres.ShapeType.roundRect, {
    x: 1.5, y: y, w: 6, h: 1.1,
    fill: { color: sys.color }
  });

  slide3.addText(sys.title, {
    x: 1.7, y: y + 0.1, w: 1.5, h: 0.4,
    fontSize: 20, fontBold: true, color: COLORS.white
  });

  slide3.addText(sys.sub, {
    x: 1.7, y: y + 0.5, w: 2, h: 0.3,
    fontSize: 12, color: COLORS.white
  });

  slide3.addText(sys.desc, {
    x: 4, y: y + 0.35, w: 3.3, h: 0.4,
    fontSize: 16, color: COLORS.white, align: "right"
  });

  if (i < 2) {
    slide3.addText("↓", {
      x: 4.2, y: y + 1.1, w: 0.6, h: 0.3,
      fontSize: 20, color: COLORS.primary, align: "center"
    });
  }
});

// ========== 第4页：汇报管理闭环 ==========
let slide4 = pres.addSlide();
slide4.background = { color: COLORS.white };

slide4.addText("汇报管理闭环", {
  x: 0.5, y: 0.3, w: 9, h: 0.8,
  fontSize: 32, fontBold: true, color: COLORS.primary
});

let loop = [
  { t: "填写", b: "计划对比" },
  { t: "点评", b: "反馈建议" },
  { t: "评分", b: "考核评估" },
  { t: "汇总", b: "决策支持" }
];

loop.forEach((item, i) => {
  let x = 0.8 + i * 2.3;

  // 上框
  slide4.addShape(pres.ShapeType.roundRect, {
    x: x, y: 1.6, w: 1.8, h: 1,
    fill: { color: COLORS.secondary }
  });
  slide4.addText(item.t, {
    x: x, y: 1.8, w: 1.8, h: 0.6,
    fontSize: 18, fontBold: true, color: COLORS.white, align: "center"
  });

  // 箭头
  slide4.addText("↓", {
    x: x + 0.6, y: 2.7, w: 0.6, h: 0.4,
    fontSize: 20, color: COLORS.primary, align: "center"
  });

  // 下框
  slide4.addShape(pres.ShapeType.roundRect, {
    x: x, y: 3.1, w: 1.8, h: 1,
    fill: { color: COLORS.primary }
  });
  slide4.addText(item.b, {
    x: x, y: 3.3, w: 1.8, h: 0.6,
    fontSize: 14, color: COLORS.white, align: "center"
  });
});

// ========== 第5页：日报格式 ==========
let slide5 = pres.addSlide();
slide5.background = { color: COLORS.white };

slide5.addText("日报四大板块", {
  x: 0.5, y: 0.3, w: 9, h: 0.8,
  fontSize: 32, fontBold: true, color: COLORS.primary
});

let parts = [
  { n: "01", t: "今日总结", c: "清晰罗列工作事项，明确完成情况及成果" },
  { n: "02", t: "经验沉淀", c: "提炼方法、心得、解决思路，突出实用性" },
  { n: "03", t: "明日计划", c: "明确核心工作，标注目标与时限" },
  { n: "04", t: "需要帮助", c: "列出需协调支持的事项" }
];

parts.forEach((p, i) => {
  let y = 1.2 + i * 1.1;

  slide5.addShape(pres.ShapeType.roundRect, {
    x: 0.5, y: y, w: 9, h: 0.95,
    fill: { color: i % 2 === 0 ? COLORS.lightGray : COLORS.white }
  });

  slide5.addText(p.n, {
    x: 0.7, y: y + 0.2, w: 0.6, h: 0.5,
    fontSize: 24, fontBold: true, color: COLORS.accent
  });

  slide5.addText(p.t, {
    x: 1.5, y: y + 0.15, w: 3, h: 0.4,
    fontSize: 18, fontBold: true, color: COLORS.primary
  });

  slide5.addText(p.c, {
    x: 1.5, y: y + 0.5, w: 7.5, h: 0.4,
    fontSize: 13, color: COLORS.text
  });
});

// ========== 第6页：经验沉淀 ==========
let slide6 = pres.addSlide();
slide6.background = { color: COLORS.white };

slide6.addText("经验沉淀", {
  x: 0.5, y: 0.3, w: 9, h: 0.8,
  fontSize: 32, fontBold: true, color: COLORS.primary
});

// 五大维度
slide6.addText("五大维度", {
  x: 0.5, y: 1.1, w: 4, h: 0.5,
  fontSize: 18, fontBold: true, color: COLORS.primary
});

let dims = ["成单经验", "踩坑教训", "技巧分享", "行业洞察", "产品心得"];
dims.forEach((d, i) => {
  let x = 0.5 + (i % 3) * 1.5;
  let y = 1.6 + Math.floor(i / 3) * 0.7;
  slide6.addShape(pres.ShapeType.roundRect, {
    x: x, y: y, w: 1.4, h: 0.55,
    fill: { color: COLORS.secondary }
  });
  slide6.addText(d, {
    x: x, y: y + 0.15, w: 1.4, h: 0.3,
    fontSize: 11, color: COLORS.white, align: "center"
  });
});

// 写作技巧
slide6.addText("写作技巧", {
  x: 5.5, y: 1.1, w: 4, h: 0.5,
  fontSize: 18, fontBold: true, color: COLORS.primary
});

slide6.addShape(pres.ShapeType.roundRect, {
  x: 5.5, y: 1.6, w: 4, h: 2.2,
  fill: { color: COLORS.lightGray }
});

slide6.addText("具体化：不要写"要细心"，而是写"发现问题""", {
  x: 5.7, y: 1.75, w: 3.6, h: 0.5,
  fontSize: 12, color: COLORS.text
});

