const PptxGenJS = require("pptxgenjs");

let pres = new PptxGenJS();

const COLORS = {
  primary: "1E3A5F",
  secondary: "4A90D9",
  accent: "F5A623",
  text: "333333",
  white: "FFFFFF",
  lightGray: "F5F5F5"
};

// Slide 1: 封面
let s1 = pres.addSlide();
s1.background = { color: COLORS.primary };
s1.addShape(pres.ShapeType.rect, { x: 0, y: 0, w: 0.3, h: 0.3, fill: { color: COLORS.secondary } });
