s1.addText("打造高效执行力团队", { x: 0.5, y: 3.2, w: 9, h: 0.6, fontSize: 24, color: COLORS.secondary, align: "center" });
s1.addText("道简网络 | 2026年3月", { x: 0.5, y: 5.5, w: 9, h: 0.4, fontSize: 16, color: COLORS.white, align: "center" });

// Slide 2: 为什么要做汇报
let s2 = pres.addSlide();
s2.background = { color: COLORS.white };
s2.addText("为什么要做汇报？", { x: 0.5, y: 0.3, w: 9, h: 0.8, fontSize: 32, fontBold: true, color: COLORS.primary });

let cards = [
  { title: "记录工作", desc: "留下痕迹，证明付出" },
  { title: "梳理思路", desc: "写的过程是思考" },
  { title: "发现问题", desc: "对比计划与完成" },
  { title: "积累经验", desc: "把经历变能力" },
  { title: "获得指导", desc: "领导是免费导师" },
  { title: "加速成长", desc: "反思中进步更快" }
];
cards.forEach((c, i) => {
  let x = 0.5 + (i % 3) * 3.1;
  let y = 1.3 + Math.floor(i / 3) * 1.8;
  s2.addShape(pres.ShapeType.roundRect, { x: x, y: y, w: 2.9, h: 1.5, fill: { color: COLORS.lightGray } });
  s2.addText(c.title, { x: x + 0.2, y: y + 0.3, w: 2.5, h: 0.5, fontSize: 18, fontBold: true, color: COLORS.primary });
  s2.addText(c.desc, { x: x + 0.2, y: y + 0.9, w: 2.5, h: 0.4, fontSize: 12, color: COLORS.text });
});
s2.addText("汇报不是任务，而是习惯", { x: 0.5, y: 5.2, w: 9, h: 0.4, fontSize: 18, fontBold: true, color: COLORS.accent, align: "center" });

