s3.background = { color: COLORS.white };
s3.addText("汇报管理三大系统", { x: 0.5, y: 0.3, w: 9, h: 0.8, fontSize: 32, fontBold: true, color: COLORS.primary });

let systems = [
  { title: "DJOS", sub: "操作系统", desc: "教员工怎么干", color: COLORS.secondary },
  { title: "DJMS", sub: "管控系统", desc: "教管理者怎么管", color: COLORS.primary },
  { title: "DJAS", sub: "应用系统", desc: "给员工用什么工具", color: COLORS.accent }
];
systems.forEach((sys, i) => {
  let y = 1.5 + i * 1.3;
