  s3.addText(sys.desc, { x: 4, y: y + 0.35, w: 3.3, h: 0.4, fontSize: 16, color: COLORS.white, align: "right" });
  if (i < 2) s3.addText("↓", { x: 4.2, y: y + 1.1, w: 0.6, h: 0.3, fontSize: 20, color: COLORS.primary, align: "center" });
