  let y = 1.2 + i * 1.1;
  s5.addShape(pres.ShapeType.roundRect, { x: 0.5, y: y, w: 9, h: 0.95, fill: { color: i % 2 === 0 ? COLORS.lightGray : COLORS.white } });
  s5.addText(p.n, { x: 0.7, y: y + 0.2, w: 0.6, h: 0.5, fontSize: 24, fontBold: true, color: COLORS.accent });
  s5.addText(p.t, { x: 1.5, y: y + 0.15, w: 3, h: 0.4, fontSize: 18, fontBold: true, color: COLORS.primary });
  s5.addText(p.c, { x: 1.5, y: y + 0.5, w: 7.5, h: 0.4, fontSize: 13, color: COLORS.text });
});

// Slide 6: 经验沉淀
let s6 = pres.addSlide();
s6.background = { color: COLORS.white };
