s6.addText("五大维度", { x: 0.5, y: 1.1, w: 4, h: 0.5, fontSize: 18, fontBold: true, color: COLORS.primary });

let dims = ["成单经验", "踩坑教训", "技巧分享", "行业洞察", "产品心得"];
dims.forEach((d, i) => {
  let x = 0.5 + (i % 3) * 1.5;
  let y = 1.6 + Math.floor(i / 3) * 0.7;
  s6.addShape(pres.ShapeType.roundRect, { x: x, y: y, w: 1.4, h: 0.55, fill: { color: COLORS.secondary } });
  s6.addText(d, { x: x, y: y + 0.15, w: 1.4, h: 0.3, fontSize: 11, color: COLORS.white, align: "center" });
